cat > /tmp/policy.rego << 'EOF'
package envoy.authz

default allow := false

# Allow requests from trusted workloads
allow if {
  spiffe_id := input.attributes.source.certificate.uri_san
  startswith(spiffe_id, "spiffe://cluster.local/ns/production/")
}
EOF

